import { callMcpSkill } from "@/lib/ai/skills/mcp";

const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main() {
  const requestedSlug = "will-ethereum-hit-5000-by-end-of-2026";

  const first = await callMcpSkill({
    toolId,
    toolName: "check_market_rules",
    args: { slug: requestedSlug }
  });

  const hasRequestedMarket =
    first &&
    typeof first.market === "string" &&
    first.market.length > 0 &&
    typeof first.description === "string" &&
    first.rulesSummary &&
    typeof first.rulesSummary === "object";

  if (hasRequestedMarket) {
    const potentialGotchas = Array.isArray(first.rulesSummary.potentialGotchas)
      ? first.rulesSummary.potentialGotchas
      : [];

    return {
      source: "requested_slug",
      slug: requestedSlug,
      market: first.market,
      resolvesYesIf: first.rulesSummary.resolvesYesIf || null,
      resolvesNoIf: first.rulesSummary.resolvesNoIf || null,
      potentialGotchas,
      gotchasCount: potentialGotchas.length,
      fetchedAt: first.fetchedAt || null
    };
  }

  const fallback = await callMcpSkill({
    toolId,
    toolName: "get_top_markets",
    args: { sortBy: "liquidity", limit: 1, category: "crypto" }
  });

  const topMarket = Array.isArray(fallback?.markets) && fallback.markets.length > 0
    ? fallback.markets[0]
    : null;

  if (!topMarket || !topMarket.slug) {
    return {
      source: "fallback_failed",
      requestedSlug,
      missingData: true,
      attemptedBranches: ["check_market_rules(requested slug)", "get_top_markets(liquidity, crypto, limit=1)"],
      stopReason: "No usable fallback market found"
    };
  }

  const second = await callMcpSkill({
    toolId,
    toolName: "check_market_rules",
    args: { slug: topMarket.slug }
  });

  const potentialGotchas = Array.isArray(second?.rulesSummary?.potentialGotchas)
    ? second.rulesSummary.potentialGotchas
    : [];

  return {
    source: "fallback_market",
    requestedSlug,
    fallbackSlug: topMarket.slug,
    fallbackMarket: topMarket.title || topMarket.slug,
    fallbackLiquidity: topMarket.liquidity,
    market: second?.market || topMarket.title || topMarket.slug,
    resolvesYesIf: second?.rulesSummary?.resolvesYesIf || null,
    resolvesNoIf: second?.rulesSummary?.resolvesNoIf || null,
    potentialGotchas,
    gotchasCount: potentialGotchas.length,
    fetchedAt: second?.fetchedAt || null
  };
}

